package jetbrains.mps.ide.httpsupport.nodeaccess.plugin;

/*Generated by MPS */

import jetbrains.mps.ide.httpsupport.runtime.base.HttpRequestHandlerBase;
import org.jetbrains.mps.openapi.model.SNodeReference;
import jetbrains.mps.project.Project;
import jetbrains.mps.ide.httpsupport.manager.plugin.HttpRequest;
import jetbrains.mps.internal.collections.runtime.ListSequence;
import org.jetbrains.mps.openapi.persistence.PersistenceFacade;
import jetbrains.mps.ide.httpsupport.runtime.base.HttpSupportUtil;
import org.jetbrains.mps.openapi.model.SNode;
import jetbrains.mps.baseLanguage.closures.runtime.Wrappers;
import io.netty.handler.codec.http.HttpResponseStatus;
import io.netty.buffer.Unpooled;
import io.netty.util.CharsetUtil;

public class NodeOpener_RequestHandler extends HttpRequestHandlerBase {
  private SNodeReference ref;
  private Project project;

  public NodeOpener_RequestHandler(HttpRequest request) {
    super(request);
  }

  @Override
  public boolean init() {
    boolean correctRequest = true;
    {
      String ref_serialized = ListSequence.fromList(this.request.getParameterValue("ref")).getElement(0);
      if (ref_serialized != null) {
        this.ref = PersistenceFacade.getInstance().createNodeReference(ref_serialized);
      } else {
        correctRequest = false;
        this.ref = null;
      }
    }
    {
      String project_serialized = ListSequence.fromList(this.request.getParameterValue("project")).getElement(0);
      if (project_serialized != null) {
        this.project = HttpSupportUtil.getProjectByName(project_serialized);
      } else {
        this.project = HttpSupportUtil.getSomeProject();
      }
    }
    return correctRequest;
  }


  @Override
  public void handle() throws Exception {
    // The project may be incorrect if the ide.httpsupport.specifyProjectInNodeURL is false
    Project projectForNode = HandlerUtil.getProjectForNode(this.project, this.ref);
    if (projectForNode != null) {
      final SNode node = HandlerUtil.openNode(projectForNode, this.ref);
      if (node != null) {
        final Wrappers._T<String> nodePresentation = new Wrappers._T<String>();
        projectForNode.getModelAccess().runReadAction(() -> nodePresentation.value = node.getPresentation());
        String text = HandlerUtil.HEADER_RESPONCE + "The requested node has been opened in MPS<br><b>Node</b>: " + nodePresentation.value + " <i>(" + node.getConcept() + ")</i><br><b>Project</b>: " + projectForNode.getName();
        this.request.sendResponse(HttpResponseStatus.OK, "text/html; charset=UTF-8", Unpooled.copiedBuffer(text, CharsetUtil.UTF_8));
      } else {
        String text = HandlerUtil.HEADER_RESPONCE + "The requested node has not been found<br><b>Node reference</b>: " + this.ref + "<br><b>Project</b>: " + projectForNode.getName();
        HandlerUtil.showNodeNotFoundPopup(projectForNode, this.ref);
        this.request.sendResponse(HttpResponseStatus.OK, "text/html; charset=UTF-8", Unpooled.copiedBuffer(text, CharsetUtil.UTF_8));
      }
    } else {
      String text = HandlerUtil.HEADER_RESPONCE + "No project is available";
      HandlerUtil.showNoProjectIsAvailablePopup();
      this.request.sendResponse(HttpResponseStatus.OK, "text/html", Unpooled.copiedBuffer(text, CharsetUtil.UTF_8));
    }
  }
}
